---
import { getCollection, getEntry, render } from "astro:content"

import Docs from "@/components/layouts/docs.astro"
import Home from "@/components/layouts/home.astro"

export async function getStaticPaths() {
  const pages = await getCollection("pages")
  return pages.map((page) => {
    return {
      params: {
        page: page.id === "index" ? undefined : page.id,
      },
      props: page,
    }
  })
}

const page = Astro.props.data
const type = page.type
const { Content } = await render(Astro.props)
const global = (await getEntry("globals", Astro.currentLocale || "en"))?.data
---

{
  type === "home" ? (
    <Home global={global} page={page}>
      <Content />
    </Home>
  ) : // ) : type === "docs" ? (
  //   <Docs global={global} page={page}>
  //     <Content />
  //   </Docs>
  null
}
